  // Define colors based on rank
  const getRankStyles = (rank: number) => {
    switch (rank) {
      case 1:
        return {
          badgeClasses:
            "bg-gradient-to-r from-yellow-400 to-yellow-500 border-yellow-400",
          textClasses: "text-yellow-900",
          ringClasses: "border-yellow-400 shadow-yellow-400/20",
          laurelColor: "#F0D87F",
        };
      case 2:
        return {
          badgeClasses:
            "bg-gradient-to-r from-slate-300 to-slate-400 border-slate-400",
          textClasses: "text-slate-800",
          ringClasses: "border-slate-400 shadow-slate-400/20",
          laurelColor: "#CDCDDC",
        };
      case 3:
        return {
          badgeClasses:
            "bg-gradient-to-r from-orange-400 to-orange-500 border-orange-400",
          textClasses: "text-orange-900",
          ringClasses: "border-orange-400 shadow-orange-400/20",
          laurelColor: "#D49E7F",
        };
      default:
        return {
          badgeClasses:
            "bg-gradient-to-r from-slate-300 to-slate-400 border-slate-400",
          textClasses: "text-slate-800",
          ringClasses: "border-slate-400 shadow-slate-400/20",
          laurelColor: "#CDCDDC",
        };
    }
  };

